120→void ULFPWorldMapEditorComponent::SelectNode(ALFPWorldMapNode* Node)
121→{
122→	// 取消之前选中节点的高亮
123→	if (SelectedNode)
124→	{
125→		SelectedNode->SetHighlighted(false);
126→	}
127→
128→	SelectedNode = Node;
129→
130→	// 高亮新选中的节点
131→	if (SelectedNode)
132→	{
133→		SelectedNode->SetHighlighted(true);
134→	}
135→
136→	OnNodeSelected.Broadcast(SelectedNode);
137→}
