139→void ULFPWorldMapEditorComponent::ApplyParamsToSelectedNode()
140→{
141→	if (!SelectedNode) return;
142→
143→	SelectedNode->NodeType = BrushNodeType;
144→	SelectedNode->BattleMapName = BrushBattleMapName;
145→	SelectedNode->StarRating = BrushStarRating;
146→	SelectedNode->bCanEscape = BrushCanEscape;
147→	SelectedNode->EventID = BrushEventID;
148→	SelectedNode->BaseGoldReward = BrushBaseGoldReward;
149→	SelectedNode->BaseFoodReward = BrushBaseFoodReward;
150→
151→	// 更新视觉（节点类型可能变了）
152→	ALFPWorldMapManager* Manager = GetWorldMapManager();
153→	if (Manager)
154→	{
155→		if (auto* VisualData = Manager->GetNodeVisualForType(BrushNodeType))
156→		{
157→			SelectedNode->SetNodeVisualData(VisualData);
158→		}
159→	}
160→
161→	UE_LOG(LogTemp, Log, TEXT("应用参数到节点 ID %d"), SelectedNode->NodeID);
162→}
