 12→
 13→	// 绑定工具按钮
 14→	if (PlaceNodeButton) PlaceNodeButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnPlaceNodeClicked);
 15→	if (RemoveNodeButton) RemoveNodeButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnRemoveNodeClicked);
 16→	if (MoveNodeButton) MoveNodeButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnMoveNodeClicked);
 17→	if (ConnectEdgeButton) ConnectEdgeButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnConnectEdgeClicked);
 18→	if (RemoveEdgeButton) RemoveEdgeButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnRemoveEdgeClicked);
 19→	if (SetParamsButton) SetParamsButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnSetParamsClicked);
 20→	if (EditBattleMapButton) EditBattleMapButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnEditBattleMapClicked);
 21→
 22→	// 绑定参数控件
 23→	if (NodeTypeComboBox) NodeTypeComboBox->OnSelectionChanged.AddDynamic(this, &ULFPWorldMapEditorWidget::OnNodeTypeChanged);
 24→	if (StarRatingInput) StarRatingInput->OnTextCommitted.AddDynamic(this, &ULFPWorldMapEditorWidget::OnStarRatingChanged);
 25→	if (CanEscapeCheckBox) CanEscapeCheckBox->OnCheckStateChanged.AddDynamic(this, &ULFPWorldMapEditorWidget::OnCanEscapeChanged);
 26→	if (BattleMapNameInput) BattleMapNameInput->OnTextCommitted.AddDynamic(this, &ULFPWorldMapEditorWidget::OnBattleMapNameChanged);
 27→	if (EventIDInput) EventIDInput->OnTextCommitted.AddDynamic(this, &ULFPWorldMapEditorWidget::OnEventIDChanged);
 28→	if (EdgeTurnCostInput) EdgeTurnCostInput->OnTextCommitted.AddDynamic(this, &ULFPWorldMapEditorWidget::OnEdgeTurnCostChanged);
 29→	if (BaseGoldRewardInput) BaseGoldRewardInput->OnTextCommitted.AddDynamic(this, &ULFPWorldMapEditorWidget::OnBaseGoldRewardChanged);
 30→	if (BaseFoodRewardInput) BaseFoodRewardInput->OnTextCommitted.AddDynamic(this, &ULFPWorldMapEditorWidget::OnBaseFoodRewardChanged);
