 39→	{
 40→		NodeTypeComboBox->ClearOptions();
 41→		NodeTypeComboBox->AddOption(TEXT("WNT_Battle"));
 42→		NodeTypeComboBox->AddOption(TEXT("WNT_Event"));
 43→		NodeTypeComboBox->AddOption(TEXT("WNT_Shop"));
 44→		NodeTypeComboBox->AddOption(TEXT("WNT_Town"));
 45→		NodeTypeComboBox->AddOption(TEXT("WNT_Boss"));
 46→		NodeTypeComboBox->AddOption(TEXT("WNT_QuestNPC"));
 47→		NodeTypeComboBox->AddOption(TEXT("WNT_SkillNode"));
 48→		NodeTypeComboBox->SetSelectedOption(TEXT("WNT_Battle"));
 49→	}
 50→
 51→	// 默认值
 52→	if (StarRatingInput) StarRatingInput->SetText(FText::FromString(TEXT("1")));
 53→	if (CanEscapeCheckBox) CanEscapeCheckBox->SetIsChecked(true);
 54→	if (EdgeTurnCostInput) EdgeTurnCostInput->SetText(FText::FromString(TEXT("1")));
