214→
215→void ULFPWorldMapEditorWidget::UpdateToolIndicator(ELFPWorldMapEditorTool NewTool)
216→{
217→	if (!CurrentToolText) return;
218→
219→	static const TMap<ELFPWorldMapEditorTool, FString> ToolNames = {
220→		{ELFPWorldMapEditorTool::WMET_None, TEXT("无")},
221→		{ELFPWorldMapEditorTool::WMET_PlaceNode, TEXT("放置节点")},
222→		{ELFPWorldMapEditorTool::WMET_RemoveNode, TEXT("删除节点")},
223→		{ELFPWorldMapEditorTool::WMET_MoveNode, TEXT("移动节点")},
224→		{ELFPWorldMapEditorTool::WMET_ConnectEdge, TEXT("连接边")},
225→		{ELFPWorldMapEditorTool::WMET_RemoveEdge, TEXT("删除边")},
226→		{ELFPWorldMapEditorTool::WMET_SetNodeParams, TEXT("设置参数")},
227→		{ELFPWorldMapEditorTool::WMET_EditBattleMap, TEXT("编辑战斗地图")},
228→	};
229→
230→	if (const FString* Name = ToolNames.Find(NewTool))
231→	{
232→		CurrentToolText->SetText(FText::FromString(*Name));
233→	}
234→}
235→
236→void ULFPWorldMapEditorWidget::UpdateNodeInfo(ALFPWorldMapNode* Node)
237→{
238→	if (!SelectedNodeInfoText) return;
239→
240→	if (!Node)
241→	{
242→		SelectedNodeInfoText->SetText(FText::FromString(TEXT("未选中")));
243→		return;
244→	}
245→
246→	// 节点类型名
247→	FString TypeStr = UEnum::GetValueAsString(Node->NodeType);
248→	TypeStr = TypeStr.RightChop(TypeStr.Find(TEXT("::")) + 2);
249→
250→	FString Info = FString::Printf(TEXT("ID: %d | 类型: %s"), Node->NodeID, *TypeStr);
251→
252→	if (Node->NodeType == ELFPWorldNodeType::WNT_Battle)
253→	{
254→		Info += FString::Printf(TEXT(" | 星级: %d | 地图: %s | 金币: %d | 食物: %d"),
255→			Node->StarRating, *Node->BattleMapName, Node->BaseGoldReward, Node->BaseFoodReward);
256→	}
257→	else if (Node->NodeType == ELFPWorldNodeType::WNT_Event)
258→	{
259→		Info += FString::Printf(TEXT(" | 事件: %s"), *Node->EventID);
260→	}
261→
262→	SelectedNodeInfoText->SetText(FText::FromString(Info));
263→}
